(async()=>{
let k='key',l=localStorage,p=l.getItem(k);
if(!p){p=prompt('输入密钥');l.setItem(k,p);}
const payload = {"salt":"XtG6TtE50qU/XFoVJGB+Xg==","iv":"ingYg1ByTnVsa95Z","data":""};
const salt = Uint8Array.from(atob(payload.salt), c => c.charCodeAt(0));
const iv = Uint8Array.from(atob(payload.iv), c => c.charCodeAt(0));
const data = Uint8Array.from(atob(payload.data), c => c.charCodeAt(0));
const encoder = new TextEncoder();
const pwKey = await crypto.subtle.importKey('raw', encoder.encode(p), 'PBKDF2', false, ['deriveKey']);
const key = await crypto.subtle.deriveKey(
	{ name: 'PBKDF2', salt: salt, iterations: 10000, hash: 'SHA-256' },
	pwKey,
	{ name: 'AES-GCM', length: 256 },
	false,
	['decrypt']
);
const decrypted = await crypto.subtle.decrypt(
	{ name: 'AES-GCM', iv: iv },
	key,
	data
);
const s = document.createElement('script');
s.type = 'module';
s.textContent = new TextDecoder().decode(decrypted);
document.getElementById('script').nextElementSibling.after(s);
})()